<?php require_once '../config/db.php'; require_once '../includes/auth.php'; require_admin(); $page_title='Payments'; if(isset($_GET['sid'],$_GET['pno'])){mysqli_query($conn,'DELETE FROM PAYMENT WHERE subscription_id='.intval($_GET['sid']).' AND payment_no='.intval($_GET['pno'])); header('Location: payments.php'); exit();} if($_SERVER['REQUEST_METHOD']==='POST'){ $stmt=mysqli_prepare($conn,'INSERT INTO PAYMENT(subscription_id,payment_no,amount,payment_date,payment_method,payment_status) VALUES(?,?,?,?,?,?)'); mysqli_stmt_bind_param($stmt,'iidsss',$_POST['subscription_id'],$_POST['payment_no'],$_POST['amount'],$_POST['payment_date'],$_POST['payment_method'],$_POST['payment_status']); mysqli_stmt_execute($stmt); header('Location: payments.php'); exit(); } $subs=mysqli_query($conn,"SELECT s.subscription_id, CONCAT(p.first_name,' ',p.last_name,' - ',mp.plan_name) title FROM SUBSCRIPTION s JOIN MEMBER m ON s.member_id=m.person_id JOIN PERSON p ON m.person_id=p.person_id JOIN MEMBERSHIP_PLAN mp ON s.plan_id=mp.plan_id"); $result=mysqli_query($conn,"SELECT pay.subscription_id, pay.payment_no, CONCAT(p.first_name,' ',p.last_name) member_name, pay.amount, pay.payment_date, pay.payment_method, pay.payment_status FROM PAYMENT pay JOIN SUBSCRIPTION s ON pay.subscription_id=s.subscription_id JOIN MEMBER m ON s.member_id=m.person_id JOIN PERSON p ON m.person_id=p.person_id ORDER BY pay.payment_date DESC"); require_once '../includes/header.php'; require_once '../includes/sidebar.php'; ?>
<div class="card form-card"><h2>Add Payment</h2><form method="POST" class="form-grid"><div><label>Subscription</label><select name="subscription_id"><?php while($s=mysqli_fetch_assoc($subs)): ?><option value="<?= $s['subscription_id'] ?>"><?= safe($s['title']) ?></option><?php endwhile; ?></select></div><div><label>Payment No</label><input class="input" type="number" name="payment_no" value="1" required></div><div><label>Amount</label><input class="input" type="number" step="0.01" name="amount" required></div><div><label>Date</label><input class="input" type="date" name="payment_date" required></div><div><label>Method</label><select name="payment_method"><option>Cash</option><option>Card</option><option>JazzCash</option><option>EasyPaisa</option><option>Bank Transfer</option></select></div><div><label>Status</label><select name="payment_status"><option>Paid</option><option>Pending</option><option>Failed</option><option>Refunded</option></select></div><div class="full"><button class="btn">Add Payment</button></div></form></div><h2 class="section-title">Payments</h2><div class="table-wrap"><table><tr><th>Subscription</th><th>Payment No</th><th>Member</th><th>Amount</th><th>Date</th><th>Method</th><th>Status</th><th>Action</th></tr><?php while($r=mysqli_fetch_assoc($result)): ?><tr><td><?= safe($r['subscription_id']) ?></td><td><?= safe($r['payment_no']) ?></td><td><?= safe($r['member_name']) ?></td><td><?= safe($r['amount']) ?></td><td><?= safe($r['payment_date']) ?></td><td><?= safe($r['payment_method']) ?></td><td><span class="badge"><?= safe($r['payment_status']) ?></span></td><td><a class="btn btn-danger" onclick="return confirm('Delete payment?')" href="payments.php?sid=<?= $r['subscription_id'] ?>&pno=<?= $r['payment_no'] ?>">Delete</a></td></tr><?php endwhile; ?></table></div><?php require_once '../includes/footer.php'; ?>
